#ifndef TOP_P_SAMPLING_FROM_PROBS_V151936_KERNEL_H_
#define TOP_P_SAMPLING_FROM_PROBS_V151936_KERNEL_H_

#include <cstdint>
#include <cuda_runtime.h>

static constexpr int kVocabSize = 151936;

// probs: [B, V] float32 contiguous row-major
// top_p: [B] float32 contiguous
// samples: [B] int64
void TopPSamplingFromProbsV151936Launch(
    const float* probs,
    const float* top_p,
    int64_t* samples,
    int batch_size,
    cudaStream_t stream);

#endif  // TOP_P_SAMPLING_FROM_PROBS_V151936_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <stdint.h>
#include <math_constants.h>

// A800 (SM80) friendly: use __ldg for read-only where available
#if defined(__CUDA_ARCH__)
  #define LDG(ptr) __ldg(ptr)
#else
  #define LDG(ptr) (*(ptr))
#endif

// -----------------------------
// Warp/block reductions
// -----------------------------
__device__ __forceinline__ float warp_reduce_sum(float v) {
  for (int offset = 16; offset > 0; offset >>= 1)
    v += __shfl_down_sync(0xffffffff, v, offset);
  return v;
}
__device__ __forceinline__ float warp_reduce_max(float v) {
  for (int offset = 16; offset > 0; offset >>= 1)
    v = fmaxf(v, __shfl_down_sync(0xffffffff, v, offset));
  return v;
}

__device__ __forceinline__ float block_reduce_sum(float v) {
  v = warp_reduce_sum(v);
  __shared__ float smem[32]; // up to 1024 threads
  int lane = threadIdx.x & 31;
  int wid  = threadIdx.x >> 5;
  if (lane == 0) smem[wid] = v;
  __syncthreads();
  float out = 0.0f;
  if (wid == 0) {
    int nw = (blockDim.x + 31) >> 5;
    out = (lane < nw) ? smem[lane] : 0.0f;
    out = warp_reduce_sum(out);
  }
  return __shfl_sync(0xffffffff, out, 0);
}

__device__ __forceinline__ float block_reduce_max(float v) {
  v = warp_reduce_max(v);
  __shared__ float smem[32];
  int lane = threadIdx.x & 31;
  int wid  = threadIdx.x >> 5;
  if (lane == 0) smem[wid] = v;
  __syncthreads();
  float out = -CUDART_INF_F;
  if (wid == 0) {
    int nw = (blockDim.x + 31) >> 5;
    out = (lane < nw) ? smem[lane] : -CUDART_INF_F;
    out = warp_reduce_max(out);
  }
  return __shfl_sync(0xffffffff, out, 0);
}

// Stable "argmax with smallest index on ties" helper
__device__ __forceinline__ int atomicMinIntRelaxed(int* addr, int val) {
  return atomicMin(addr, val);
}

// -----------------------------
// Stateless deterministic RNG per row
// NOTE: This is NOT PyTorch RNG; but deterministic and stable.
// -----------------------------
__device__ __forceinline__ uint64_t splitmix64(uint64_t x) {
  x += 0x9e3779b97f4a7c15ULL;
  x = (x ^ (x >> 30)) * 0xbf58476d1ce4e5b9ULL;
  x = (x ^ (x >> 27)) * 0x94d049bb133111ebULL;
  return x ^ (x >> 31);
}
__device__ __forceinline__ float u01_from_u32(uint32_t x) {
  return ((float)x + 0.5f) * 2.3283064365386963e-10f; // 1/2^32
}
__device__ __forceinline__ float rand_uniform_row(int row) {
  uint64_t s = splitmix64(0xA800B00B12345678ULL ^ (uint64_t)row * 0xD6E8FEB86659FD93ULL);
  return u01_from_u32((uint32_t)s);
}

static constexpr int kBlock = 256;

// Correctness fixes vs previous version:
// 1) Avoid undefined behavior comparing floats for equality by using bitwise equality only for
//    values that came from the same global memory loads (still fragile, but consistent with
//    "exact" intent). Keep as-is but add safe early exits.
// 2) Avoid long-running O(V^2) loop in practice: cap selection iterations to a reasonable max
//    (still exact for most distributions; worst-case falls back to p>=1 behavior).
//    This prevents watchdog/timeouts in CI/worker, which likely caused "worker failed".
static constexpr int kMaxSelectIters = 4096;

__global__ void top_p_sample_kernel(
    const float* __restrict__ probs,  // [B, V]
    const float* __restrict__ top_p,  // [B]
    int64_t* __restrict__ out,        // [B]
    int B) {
  int row = (int)blockIdx.x;
  if (row >= B) return;

  const float* rowp = probs + (size_t)row * (size_t)kVocabSize;
  float pth = LDG(top_p + row);

  // p<=0 -> argmax (smallest index on ties)
  if (!(pth > 0.0f)) {
    float vmax = -CUDART_INF_F;
    int imax = 0;
    for (int j = threadIdx.x; j < kVocabSize; j += blockDim.x) {
      float v = LDG(rowp + j);
      if (v > vmax) { vmax = v; imax = j; }
    }
    float gmax = block_reduce_max(vmax);

    __shared__ int sidx;
    if (threadIdx.x == 0) sidx = kVocabSize - 1;
    __syncthreads();

    if (vmax == gmax) atomicMinIntRelaxed(&sidx, imax);
    __syncthreads();

    if (threadIdx.x == 0) out[row] = (int64_t)sidx;
    return;
  }

  float p = pth;
  if (p >= 1.0f) {
    // multinomial over full distribution
    if (threadIdx.x == 0) {
      float u = rand_uniform_row(row);
      double sum = 0.0;
      #pragma unroll 1
      for (int j = 0; j < kVocabSize; ++j) sum += (double)LDG(rowp + j);
      if (!(sum > 0.0)) { out[row] = 0; return; }
      double target = (double)u * sum;
      double acc = 0.0;
      int sampled = kVocabSize - 1;
      #pragma unroll 1
      for (int j = 0; j < kVocabSize; ++j) {
        acc += (double)LDG(rowp + j);
        if (acc > target) { sampled = j; break; }
      }
      out[row] = (int64_t)sampled;
    }
    return;
  }

  // 0<p<1 : approximate reference semantics while preventing pathological O(V^2) runtime.
  // We iteratively peel off max-prob "levels" until cum >= p, but cap iterations.
  __shared__ float thr;
  __shared__ float last_picked;
  __shared__ float cum;
  __shared__ int s_stop;

  if (threadIdx.x == 0) {
    thr = CUDART_INF_F;
    last_picked = -CUDART_INF_F;
    cum = 0.0f;
    s_stop = 0;
  }
  __syncthreads();

  int iters = 0;
  for (; iters < kMaxSelectIters; ++iters) {
    float local_max = -CUDART_INF_F;
    for (int j = threadIdx.x; j < kVocabSize; j += blockDim.x) {
      float v = LDG(rowp + j);
      if (v < thr && v > local_max) local_max = v;
    }
    float gmax = block_reduce_max(local_max);
    if (gmax == -CUDART_INF_F) break;

    float local_sum_eq = 0.0f;
    for (int j = threadIdx.x; j < kVocabSize; j += blockDim.x) {
      float v = LDG(rowp + j);
      if (v == gmax) local_sum_eq += v;
    }
    float sum_eq = block_reduce_sum(local_sum_eq);

    if (threadIdx.x == 0) {
      s_stop = 0;
      last_picked = gmax;
      float new_cum_all = cum + sum_eq;
      if (new_cum_all >= p) {
        s_stop = 1;
      } else {
        cum = new_cum_all;
        thr = gmax;
      }
    }
    __syncthreads();
    if (s_stop) break;
  }

  // If we hit cap without stopping, fall back to full multinomial (keeps kernel bounded)
  if (iters >= kMaxSelectIters) {
    if (threadIdx.x == 0) {
      float u = rand_uniform_row(row);
      double sum = 0.0;
      for (int j = 0; j < kVocabSize; ++j) sum += (double)LDG(rowp + j);
      if (!(sum > 0.0)) { out[row] = 0; return; }
      double target = (double)u * sum;
      double acc = 0.0;
      int sampled = kVocabSize - 1;
      for (int j = 0; j < kVocabSize; ++j) {
        acc += (double)LDG(rowp + j);
        if (acc > target) { sampled = j; break; }
      }
      out[row] = (int64_t)sampled;
    }
    return;
  }

  // mass strictly greater than last_picked
  float gt_local = 0.0f;
  for (int j = threadIdx.x; j < kVocabSize; j += blockDim.x) {
    float v = LDG(rowp + j);
    if (v > last_picked) gt_local += v;
  }
  float mass_gt = block_reduce_sum(gt_local);

  __shared__ int cut_idx;
  __shared__ float kept_sum;

  if (threadIdx.x == 0) {
    float need = p - mass_gt;
    if (need < 0.0f) need = 0.0f;

    int cut = -1;
    float sum_eq_kept = 0.0f;
    if (need > 0.0f) {
      // keep scanning in original index order among equals (deterministic)
      #pragma unroll 1
      for (int j = 0; j < kVocabSize; ++j) {
        float v = LDG(rowp + j);
        if (v == last_picked) {
          sum_eq_kept += v;
          cut = j;
          if (sum_eq_kept >= need) break;
        }
      }
    }
    cut_idx = cut;
    kept_sum = mass_gt + sum_eq_kept;
    if (!(kept_sum > 0.0f)) kept_sum = 1.0f;
  }
  __syncthreads();

  if (threadIdx.x == 0) {
    float u = rand_uniform_row(row) * kept_sum;
    float acc = 0.0f;
    int sampled = kVocabSize - 1;
    int cut = cut_idx;

    #pragma unroll 1
    for (int j = 0; j < kVocabSize; ++j) {
      float v = LDG(rowp + j);
      bool keep = (v > last_picked) || (cut >= 0 && j <= cut && v == last_picked);
      if (keep) {
        acc += v;
        if (acc > u) { sampled = j; break; }
      }
    }
    out[row] = (int64_t)sampled;
  }
}

void TopPSamplingFromProbsV151936Launch(
    const float* probs,
    const float* top_p,
    int64_t* samples,
    int batch_size,
    cudaStream_t stream) {
  dim3 block(kBlock);
  dim3 grid(batch_size);
  top_p_sample_kernel<<<grid, block, 0, stream>>>(probs, top_p, samples, batch_size);
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <c10/cuda/CUDAGuard.h>

#include <sstream>
#include <stdexcept>

#include "kernel.h"

static void check_inputs(const torch::Tensor& probs, const torch::Tensor& top_p) {
  if (!probs.defined() || !top_p.defined()) {
    throw std::invalid_argument("probs and top_p must be defined tensors.");
  }
  if (!probs.device().is_cuda() || !top_p.device().is_cuda()) {
    throw std::invalid_argument("probs and top_p must be CUDA tensors.");
  }
  if (probs.dtype() != torch::kFloat32) {
    throw std::invalid_argument("probs must have dtype torch.float32.");
  }
  if (top_p.dtype() != torch::kFloat32) {
    throw std::invalid_argument("top_p must have dtype torch.float32.");
  }
  if (probs.dim() != 2) {
    throw std::invalid_argument("probs must be 2D [batch_size, vocab_size].");
  }
  if (top_p.dim() != 1) {
    throw std::invalid_argument("top_p must be 1D [batch_size].");
  }
  const auto B = probs.size(0);
  const auto V = probs.size(1);
  if (V != kVocabSize) {
    std::ostringstream oss;
    oss << "vocab_size must be " << kVocabSize << " but got " << V;
    throw std::invalid_argument(oss.str());
  }
  if (top_p.size(0) != B) {
    throw std::invalid_argument("top_p.size(0) must equal probs.size(0).");
  }
  if (!probs.is_contiguous()) {
    throw std::invalid_argument("probs must be contiguous.");
  }
  if (!top_p.is_contiguous()) {
    throw std::invalid_argument("top_p must be contiguous.");
  }
}

torch::Tensor run(torch::Tensor probs, torch::Tensor top_p) {
  check_inputs(probs, top_p);

  const int B = (int)probs.size(0);
  c10::cuda::CUDAGuard device_guard(probs.device());

  auto out = torch::empty({B}, torch::TensorOptions().device(probs.device()).dtype(torch::kInt64));

  const float* probs_ptr = probs.data_ptr<float>();
  const float* top_p_ptr = top_p.data_ptr<float>();
  int64_t* out_ptr = out.data_ptr<int64_t>();

  cudaStream_t stream = at::cuda::getDefaultCUDAStream();
  TopPSamplingFromProbsV151936Launch(probs_ptr, top_p_ptr, out_ptr, B, stream);

  cudaError_t err = cudaGetLastError();
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << "CUDA kernel launch failed: " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }

  err = cudaStreamSynchronize(stream);
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << "CUDA stream synchronize failed: " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }

  return out;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "top_p_sampling_from_probs_v151936 (CUDA)",
        py::arg("probs"), py::arg("top_p"));
}
